from langflow.custom import Component
from langflow.io import MessageTextInput, IntInput, SecretStrInput, Output
from langflow.schema.message import Message
import os

class AstraDBSacredTextsTool(Component):
    display_name = "AstraDB Sacred Texts Search"
    description = "Search the vectorized archive of Sacred Texts stored in AstraDB using pre-computed embeddings."
    icon = "BookOpen"
    name = "AstraDBSacredTexts"

    inputs = [
        MessageTextInput(name="search_query", display_name="Search Query", info="The query to search against the sacred texts vector database.", value="", tool_mode=True, required=True),
        MessageTextInput(name="collection_name", display_name="Collection Name", info="The AstraDB collection containing sacred texts embeddings.", value="sphere", tool_mode=False, required=False),
        IntInput(name="top_k", display_name="Top K Results", info="Number of similar documents to retrieve.", value=5, tool_mode=False, required=False),
        SecretStrInput(name="astra_token", display_name="AstraDB Token", info="AstraDB API token with access to the vector collection.", value="", tool_mode=False, required=False),
        MessageTextInput(name="astra_endpoint", display_name="AstraDB Endpoint", info="The AstraDB database endpoint URL.", value="https://c3159809-d144-4510-848c-e0a621a35a5e-us-east1.apps.astra.datastax.com", tool_mode=False, required=False),
        IntInput(name="embedding_dimension", display_name="Embedding Dimension", info="Dimension of vector embeddings (1536 for OpenAI text-embedding-3-large).", value=1536, tool_mode=False, required=False),
        SecretStrInput(name="openai_api_key", display_name="OpenAI API Key", info="OpenAI API key for generating query embeddings.", value="", tool_mode=False, required=False),
    ]

    outputs = [Output(display_name="Search Results", name="search_results", method="perform_search"), Output(display_name="Tool", name="component_as_tool", method="perform_search", tool_mode=True)]

    def perform_search(self) -> Message:
        query = self.search_query
        if not query:
            return Message(text="Error: No search query provided.")

        astra_token = self.astra_token or os.getenv("ASTRA_DB_TOKEN", "")
        astra_endpoint = self.astra_endpoint or os.getenv("ASTRA_DB_ENDPOINT", "")
        openai_api_key = self.openai_api_key or os.getenv("OPENAI_API_KEY", "")

        if not astra_token:
            return Message(text="Error: AstraDB token is required. Set ASTRA_DB_TOKEN environment variable or provide it in the component.")
        if not astra_endpoint:
            return Message(text="Error: AstraDB endpoint is required. Set ASTRA_DB_ENDPOINT environment variable or provide it in the component.")
        if not openai_api_key:
            return Message(text="Error: OpenAI API key is required for query embedding generation. Set OPENAI_API_KEY environment variable or provide it in the component.")

        try:
            from openai import OpenAI
            client = OpenAI(api_key=openai_api_key)
            response = client.embeddings.create(model="text-embedding-3-large", input=query)
            query_embedding = response.data[0].embedding

            from astrapy import DataAPIClient
            astra_client = DataAPIClient(token=astra_token)
            db = astra_client.get_database_by_api_endpoint(astra_endpoint)
            collection = db.get_collection(self.collection_name)

            results = collection.find(filter={}, sort={"$vector": query_embedding}, limit=self.top_k, projection={"text": True, "title": True, "source": True, "tradition": True, "location": True})

            formatted_results = []
            for i, doc in enumerate(results, 1):
                text = doc.get("text", "")
                title = doc.get("title", "Unknown Text")
                source = doc.get("source", "Unknown Source")
                tradition = doc.get("tradition", "General")
                location = doc.get("location", "")
                formatted_results.append(f"--- Result {i} ---\nTitle: {title}\nSource: {source}\nTradition: {tradition}\nLocation: {location}\nExcerpt: {text[:1200]}\n")

            if not formatted_results:
                return Message(text="No relevant sacred texts found for this query in the 'sphere' collection.")

            output = "\n\n".join(formatted_results)
            return Message(text=output)

        except ImportError as e:
            missing_lib = str(e).split("'")[1] if "'" in str(e) else "required library"
            return Message(text=f"Error: {missing_lib} is required. Install it with: pip install {missing_lib}")
        except Exception as e:
            return Message(text=f"AstraDB search error: {str(e)}\n\nTip: Verify your credentials, that the 'sphere' collection exists, and that it contains vector data.")

from langflow.custom import Component
from langflow.io import MessageTextInput, IntInput, Output
from langflow.schema.message import Message

class WikipediaSearchTool(Component):
    display_name = "Wikipedia Search"
    description = "Search Wikipedia for contextual knowledge, historical background, cultural information, religious history, biographical details, and general encyclopedic information."
    icon = "Globe"
    name = "WikipediaSearch"

    inputs = [
        MessageTextInput(name="search_query", display_name="Search Query", info="The query to search on Wikipedia.", value="", tool_mode=True, required=True),
        IntInput(name="num_results", display_name="Number of Results", info="Number of Wikipedia articles to retrieve (max 5).", value=3, tool_mode=False, required=False),
        MessageTextInput(name="language", display_name="Language", info="Wikipedia language code (e.g., 'en', 'fr', 'de', 'sa', 'zh').", value="en", tool_mode=False, required=False),
    ]

    outputs = [Output(display_name="Search Results", name="search_results", method="search_wikipedia"), Output(display_name="Tool", name="component_as_tool", method="search_wikipedia", tool_mode=True)]

    def search_wikipedia(self) -> Message:
        query = self.search_query
        if not query:
            return Message(text="Error: No search query provided.")

        try:
            import requests
            search_url = f"https://{self.language}.wikipedia.org/w/api.php"
            search_params = {"action": "query", "list": "search", "srsearch": query, "srlimit": min(self.num_results, 5), "format": "json", "utf8": 1}
            resp = requests.get(search_url, params=search_params, timeout=15)
            resp.raise_for_status()
            data = resp.json()
            search_results = data.get("query", {}).get("search", [])

            if not search_results:
                return Message(text=f"No Wikipedia results found for '{query}'.")

            formatted = []
            for result in search_results:
                title = result.get("title", "Untitled")
                snippet = result.get("snippet", "").replace("<span class='searchmatch'>", "").replace("</span>", "")
                page_id = result.get("pageid", "")
                url = f"https://{self.language}.wikipedia.org/?curid={page_id}"

                extract_params = {"action": "query", "pageids": page_id, "prop": "extracts", "exintro": False, "explaintext": True, "exsentences": 8, "format": "json"}
                extract_resp = requests.get(search_url, params=extract_params, timeout=15)
                extract_data = extract_resp.json()
                pages = extract_data.get("query", {}).get("pages", {})
                page_info = pages.get(str(page_id), {})
                extract = page_info.get("extract", snippet)[:1500]

                formatted.append(f"--- Wikipedia: {title} ---\nURL: {url}\nExtract: {extract}\n")

            output = f"Wikipedia search results for '{query}':\n\n" + "\n\n".join(formatted)
            return Message(text=output)

        except ImportError:
            return Message(text="Error: 'requests' library is required for Wikipedia search. Install it with: pip install requests")
        except requests.Timeout:
            return Message(text="Wikipedia search timed out. Please try again.")
        except Exception as e:
            return Message(text=f"Wikipedia search error: {str(e)}")
